  source_type text not null,
  entity_type text not null,
  enabled boolean not null default true,
  risk_tier text not null default 'low'::text,
  rule_config jsonb not null default '{}'::jsonb,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  constraint twin_discovery_rules_risk_tier_check CHECK ((risk_tier = ANY (ARRAY['low'::text, 'moderate'::text, 'high'::text, 'critical'::text]))),
  constraint twin_discovery_rules_pkey PRIMARY KEY (id),
  constraint twin_discovery_rules_rule_code_key UNIQUE (rule_code)
);
create table constitution.twin_discovery_snapshots (
  id uuid not null default gen_random_uuid(),
  source_system_id uuid not null,
  status text not null default 'running'::text,
  started_at timestamp with time zone not null default now(),
  completed_at timestamp with time zone,
  entities_seen integer not null default 0,
  entities_created integer not null default 0,
  entities_updated integer not null default 0,
  relationships_created integer not null default 0,
  source_cursor jsonb not null default '{}'::jsonb,
  evidence jsonb not null default '{}'::jsonb,
  error_detail text,
  created_at timestamp with time zone not null default now(),
  entities_missing integer not null default 0,
  constraint twin_discovery_snapshots_status_check CHECK ((status = ANY (ARRAY['queued'::text, 'running'::text, 'succeeded'::text, 'partial'::text, 'failed'::text]))),
  constraint twin_discovery_snapshots_pkey PRIMARY KEY (id)
);
create table constitution.twin_entities (
  id uuid not null default gen_random_uuid(),
  enterprise_id text not null,
  entity_type text not null,
  name text not null,
  status text not null default 'active'::text,
  source_system_id uuid,
  source_native_id text,
  canonical_uri text,
  description text,
  criticality text not null default 'normal'::text,
  owner_ai_organization_id uuid,
  artifact_id uuid,
  attributes jsonb not null default '{}'::jsonb,
  tags text[] not null default '{}'::text[],
  content_hash text,
  first_seen_at timestamp with time zone not null default now(),
  last_seen_at timestamp with time zone not null default now(),
  retired_at timestamp with time zone,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  constraint twin_entities_criticality_check CHECK ((criticality = ANY (ARRAY['low'::text, 'normal'::text, 'high'::text, 'critical'::text]))),
  constraint twin_entities_status_check CHECK ((status = ANY (ARRAY['planned'::text, 'active'::text, 'degraded'::text, 'retired'::text, 'unknown'::text]))),
  constraint twin_entities_pkey PRIMARY KEY (id),
  constraint twin_entities_enterprise_id_key UNIQUE (enterprise_id),
  constraint twin_entities_source_system_id_source_native_id_key UNIQUE NULLS NOT DISTINCT (source_system_id, source_native_id)
);
create table constitution.twin_health_metrics (
  id uuid not null default gen_random_uuid(),
  metric_code text not null,
  name text not null,
  domain text not null,
  description text not null,
  unit text not null,
  weight numeric(8,4) not null default 1,
  direction text not null default 'higher_is_better'::text,
  target_config jsonb not null default '{}'::jsonb,
  status text not null default 'active'::text,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  constraint twin_health_metrics_direction_check CHECK ((direction = ANY (ARRAY['higher_is_better'::text, 'lower_is_better'::text, 'target_range'::text]))),
  constraint twin_health_metrics_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'active'::text, 'retired'::text]))),
  constraint twin_health_metrics_pkey PRIMARY KEY (id),
  constraint twin_health_metrics_metric_code_key UNIQUE (metric_code)
);
create table constitution.twin_health_snapshots (
  id uuid not null default gen_random_uuid(),
  metric_id uuid not null,
  entity_id uuid,
  measured_at timestamp with time zone not null default now(),
  raw_value numeric not null,
  normalized_score numeric(6,3),
  status text not null default 'healthy'::text,
  evidence jsonb not null default '{}'::jsonb,
  created_at timestamp with time zone not null default now(),
  constraint twin_health_snapshots_normalized_score_check CHECK (((normalized_score >= (0)::numeric) AND (normalized_score <= (100)::numeric))),
  constraint twin_health_snapshots_status_check CHECK ((status = ANY (ARRAY['healthy'::text, 'watch'::text, 'degraded'::text, 'critical'::text, 'unknown'::text]))),
  constraint twin_health_snapshots_pkey PRIMARY KEY (id)
);
create table constitution.twin_impact_analyses (
  id uuid not null default gen_random_uuid(),
  analysis_code text not null,
  title text not null,
  change_description text not null,
  trigger_entity_id uuid,
  work_item_id uuid,
  status text not null default 'queued'::text,
  risk_level text,
  summary text,
  assumptions jsonb not null default '[]'::jsonb,
  recommendations jsonb not null default '[]'::jsonb,
  requested_by text,
  started_at timestamp with time zone,
  completed_at timestamp with time zone,
  created_at timestamp with time zone not null default now(),
  constraint twin_impact_analyses_risk_level_check CHECK ((risk_level = ANY (ARRAY['low'::text, 'moderate'::text, 'high'::text, 'critical'::text]))),
  constraint twin_impact_analyses_status_check CHECK ((status = ANY (ARRAY['queued'::text, 'running'::text, 'completed'::text, 'failed'::text, 'cancelled'::text]))),
  constraint twin_impact_analyses_pkey PRIMARY KEY (id),
  constraint twin_impact_analyses_analysis_code_key UNIQUE (analysis_code)
);
create table constitution.twin_impact_findings (
  id uuid not null default gen_random_uuid(),
  impact_analysis_id uuid not null,
  affected_entity_id uuid,
  impact_type text not null,
  severity text not null default 'moderate'::text,
  confidence numeric(5,4) not null default 1.0,
  finding text not null,
  required_action text,
  evidence jsonb not null default '[]'::jsonb,
  created_at timestamp with time zone not null default now(),
  constraint twin_impact_findings_confidence_check CHECK (((confidence >= (0)::numeric) AND (confidence <= (1)::numeric))),
  constraint twin_impact_findings_severity_check CHECK ((severity = ANY (ARRAY['informational'::text, 'low'::text, 'moderate'::text, 'high'::text, 'critical'::text]))),
  constraint twin_impact_findings_pkey PRIMARY KEY (id)
);
create table constitution.twin_relationships (
  id uuid not null default gen_random_uuid(),
  source_entity_id uuid not null,
  target_entity_id uuid not null,
  relationship_type text not null,
  directionality text not null default 'directed'::text,
  strength numeric(5,4) not null default 1.0,
  confidence numeric(5,4) not null default 1.0,
  source_system_id uuid,
  evidence jsonb not null default '[]'::jsonb,
  metadata jsonb not null default '{}'::jsonb,
  valid_from timestamp with time zone not null default now(),
  valid_to timestamp with time zone,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  constraint twin_relationships_confidence_check CHECK (((confidence >= (0)::numeric) AND (confidence <= (1)::numeric))),
  constraint twin_relationships_directionality_check CHECK ((directionality = ANY (ARRAY['directed'::text, 'bidirectional'::text]))),
  constraint twin_relationships_strength_check CHECK (((strength >= (0)::numeric) AND (strength <= (1)::numeric))),
  constraint twin_relationships_pkey PRIMARY KEY (id),
  constraint twin_relationships_source_entity_id_target_entity_id_relati_key UNIQUE (source_entity_id, target_entity_id, relationship_type)
);
create table constitution.twin_simulation_results (
  id uuid not null default gen_random_uuid(),
  simulation_id uuid not null,
  result_type text not null,
  outcome text not null,
  probability numeric(5,4),
  impact_score numeric(10,4),
  affected_entities jsonb not null default '[]'::jsonb,
  recommendations jsonb not null default '[]'::jsonb,
  evidence jsonb not null default '[]'::jsonb,
  created_at timestamp with time zone not null default now(),
  constraint twin_simulation_results_probability_check CHECK (((probability >= (0)::numeric) AND (probability <= (1)::numeric))),
  constraint twin_simulation_results_pkey PRIMARY KEY (id)
);
create table constitution.twin_simulations (
  id uuid not null default gen_random_uuid(),
  simulation_code text not null,
  title text not null,
  scenario text not null,
  status text not null default 'draft'::text,
  requested_by text,
  founder_approval_required boolean not null default false,
  baseline_snapshot jsonb not null default '{}'::jsonb,
  assumptions jsonb not null default '[]'::jsonb,
  parameters jsonb not null default '{}'::jsonb,
  started_at timestamp with time zone,
  completed_at timestamp with time zone,
  created_at timestamp with time zone not null default now(),
  constraint twin_simulations_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'queued'::text, 'running'::text, 'completed'::text, 'failed'::text, 'cancelled'::text]))),
  constraint twin_simulations_pkey PRIMARY KEY (id),
  constraint twin_simulations_simulation_code_key UNIQUE (simulation_code)
);
create table constitution.twin_source_systems (
  id uuid not null default gen_random_uuid(),
  source_code text not null,
  name text not null,
  source_type text not null,
  status text not null default 'planned'::text,
  authority_rank integer not null default 100,
  connector_ref text,
  discovery_policy jsonb not null default '{}'::jsonb,
  metadata jsonb not null default '{}'::jsonb,
  last_discovered_at timestamp with time zone,
  created_at timestamp with time zone not null default now(),
  updated_at timestamp with time zone not null default now(),
  constraint twin_source_systems_source_type_check CHECK ((source_type = ANY (ARRAY['database'::text, 'repository'::text, 'deployment'::text, 'workspace'::text, 'document_store'::text, 'analytics'::text, 'observability'::text, 'external'::text]))),
  constraint twin_source_systems_status_check CHECK ((status = ANY (ARRAY['planned'::text, 'connected'::text, 'degraded'::text, 'disabled'::text]))),
  constraint twin_source_systems_pkey PRIMARY KEY (id),
  constraint twin_source_systems_source_code_key UNIQUE (source_code)
);

