-- Functions
CREATE OR REPLACE FUNCTION constitution.build_decision_recommendation(p_experiment_id uuid, p_decision_question text, p_requested_by text DEFAULT 'Founder'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'constitution', 'public'
AS $function$
declare v_request uuid; v_rec uuid; v_candidate uuid; v_name text; v_ev numeric; v_score numeric; v_conf numeric; v_code text; r record;
begin
select sc.id,sc.name,e.expected_value,e.risk_adjusted_score,e.confidence into v_candidate,v_name,v_ev,v_score,v_conf
from constitution.strategy_candidates sc
join lateral (select * from constitution.strategy_simulation_evaluations x where x.experiment_id=p_experiment_id and x.candidate_id=sc.id order by x.created_at desc limit 1) e on true
where sc.experiment_id=p_experiment_id and sc.status in ('champion','eligible','challenger') and coalesce((e.constraint_results->>'passed')::boolean,true)
order by e.risk_adjusted_score desc nulls last,e.confidence desc limit 1;
if v_candidate is null then raise exception 'No constitutionally eligible evaluated candidate'; end if;
v_code:='ESL-006-'||to_char(clock_timestamp(),'YYYYMMDDHH24MISSMS')||'-'||substr(gen_random_uuid()::text,1,8);
insert into constitution.decision_intelligence_requests(request_code,experiment_id,requested_by,decision_question,status) values(replace(v_code,'ESL-006-','DIR-'),p_experiment_id,p_requested_by,p_decision_question,'processing') returning id into v_request;
insert into constitution.decision_recommendations(request_id,experiment_id,selected_candidate_id,recommendation_code,recommendation_status,executive_recommendation,decision_summary,confidence,confidence_band,expected_value,risk_adjusted_score,evidence_strength,uncertainty_summary,approval_status)
values(v_request,p_experiment_id,v_candidate,v_code,'ready','Recommend '||v_name||'. It has the strongest eligible risk-adjusted result and remains subject to Founder approval.',jsonb_build_object('question',p_decision_question,'recommended_option',v_name,'external_execution_authorized',false),coalesce(v_conf,0),case when coalesce(v_conf,0)>=.9 then 'very_high' when coalesce(v_conf,0)>=.75 then 'high' when coalesce(v_conf,0)>=.55 then 'moderate' else 'low' end,v_ev,v_score,coalesce(v_conf,0),jsonb_build_object('residual_uncertainty',1-coalesce(v_conf,0),'recommendation_can_change',true),'pending') returning id into v_rec;
for r in select sc.id,e.expected_value,e.risk_adjusted_score,e.confidence,e.metric_results,e.constraint_results,e.robustness_results,row_number() over(order by case when coalesce((e.constraint_results->>'passed')::boolean,true) then 0 else 1 end,e.risk_adjusted_score desc nulls last,e.confidence desc) rn from constitution.strategy_candidates sc join lateral(select * from constitution.strategy_simulation_evaluations x where x.experiment_id=p_experiment_id and x.candidate_id=sc.id order by x.created_at desc limit 1)e on true where sc.experiment_id=p_experiment_id loop
insert into constitution.decision_option_assessments(recommendation_id,candidate_id,rank,option_status,expected_value,risk_adjusted_score,confidence,strengths,weaknesses,tradeoffs,constraint_findings,why_selected_or_rejected)
values(v_rec,r.id,r.rn,case when not coalesce((r.constraint_results->>'passed')::boolean,true) then 'ineligible' when r.id=v_candidate then 'recommended' else 'alternative' end,r.expected_value,r.risk_adjusted_score,r.confidence,jsonb_build_array(jsonb_build_object('risk_adjusted_score',r.risk_adjusted_score),jsonb_build_object('confidence',r.confidence)),case when not coalesce((r.constraint_results->>'passed')::boolean,true) then jsonb_build_array(r.constraint_results) else '[]'::jsonb end,jsonb_build_object('metrics',r.metric_results,'robustness',r.robustness_results),r.constraint_results,case when r.id=v_candidate then 'Highest eligible risk-adjusted score.' when not coalesce((r.constraint_results->>'passed')::boolean,true) then 'Failed a hard constraint.' else 'Eligible but ranked below the recommendation.' end);
end loop;
insert into constitution.decision_explanation_factors(recommendation_id,factor_type,factor_name,direction,importance,explanation,evidence_refs,uncertainty) values
(v_rec,'objective','Risk-adjusted performance','supports',.95,'The selected option ranked first among eligible candidates.',jsonb_build_array(jsonb_build_object('candidate_id',v_candidate,'score',v_score)),1-coalesce(v_conf,0)),
(v_rec,'constraint','Constitutional eligibility','supports',1,'Strategies failing hard constraints were excluded.','[]'::jsonb,0),
(v_rec,'dissent','Alternatives remain viable','conditional',.55,'A lower-ranked option may become preferable if assumptions or objective weights change.','[]'::jsonb,.45);
insert into constitution.decision_sensitivity_findings(recommendation_id,variable_name,baseline_value,tested_range,impact_score,switch_threshold,would_change_recommendation,explanation)
select v_rec,key,value,jsonb_build_object('source','objective_weights'),least(1,greatest(0,coalesce((value#>>'{}')::numeric,0))),jsonb_build_object('status','counterfactual_rescoring_required'),true,'Changing this objective weight may alter the ranking.' from constitution.strategy_evolution_experiments e,lateral jsonb_each(e.objective_weights) where e.id=p_experiment_id;
insert into constitution.decision_explainability_audit(recommendation_id,event_type,actor,event_payload) values(v_rec,'recommendation_built',p_requested_by,jsonb_build_object('experiment_id',p_experiment_id,'selected_candidate_id',v_candidate,'approval_required',true));
update constitution.decision_intelligence_requests set status='awaiting_approval',updated_at=now() where id=v_request;
return v_rec;
end $function$;
CREATE OR REPLACE FUNCTION constitution.generate_scenario_set(p_request_id uuid, p_seed bigint DEFAULT NULL::bigint)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'constitution', 'public'
AS $function$
declare
  v_request constitution.scenario_generation_requests%rowtype;
  v_run_id uuid := gen_random_uuid();
  v_run_code text;
  v_template record;
  v_i integer := 0;
  v_target integer;
  v_scenario_id uuid;
  v_class_count integer;
  v_probability numeric;
  v_severity numeric;
  v_novelty numeric;
  v_plausibility numeric;
begin
  select * into v_request from constitution.scenario_generation_requests where id=p_request_id for update;
  if not found then raise exception 'Scenario generation request not found'; end if;
  if jsonb_typeof(v_request.baseline_facts) <> 'object' then raise exception 'baseline_facts must be a JSON object'; end if;
  if jsonb_typeof(v_request.decision_options) <> 'array' or jsonb_array_length(v_request.decision_options)=0 then raise exception 'At least one decision option is required'; end if;

  v_target := v_request.requested_scenario_count;
  v_run_code := 'ESL-RUN-' || to_char(clock_timestamp(),'YYYYMMDDHH24MISSMS') || '-' || substr(v_run_id::text,1,8);

  update constitution.scenario_generation_requests set status='generating', updated_at=clock_timestamp() where id=p_request_id;
  insert into constitution.scenario_generation_runs(id,run_code,request_id,generator_version,generation_mode,seed,input_snapshot)
  values(v_run_id,v_run_code,p_request_id,'ESL-002.1','rules_plus_model',p_seed,
    jsonb_build_object('objective',v_request.objective,'facts',v_request.baseline_facts,'options',v_request.decision_options,'constraints',v_request.known_constraints));

  for v_template in
    select * from constitution.scenario_templates
    where active and (domain=v_request.domain or domain='general')
    order by case scenario_class when 'baseline' then 1 when 'counterfactual' then 2 when 'optimistic' then 3 when 'adverse' then 4 when 'stress' then 5 else 6 end
  loop
    v_class_count := case v_template.scenario_class
      when 'baseline' then greatest(1,ceil(v_target*0.20)::int)
      when 'counterfactual' then greatest(1,ceil(v_target*0.20)::int)
      when 'optimistic' then greatest(1,ceil(v_target*0.15)::int)
      when 'adverse' then greatest(1,ceil(v_target*0.20)::int)
      when 'stress' then greatest(1,ceil(v_target*0.15)::int)
      else greatest(1,v_target - v_i)
    end;
    for j in 1..v_class_count loop
      exit when v_i >= v_target;
      v_i := v_i + 1;
      v_scenario_id := gen_random_uuid();
      v_probability := case v_template.scenario_class when 'baseline' then 0.45 when 'optimistic' then 0.18 when 'adverse' then 0.20 when 'stress' then 0.09 when 'edge' then 0.03 else 0.05 end;
      v_severity := case v_template.scenario_class when 'optimistic' then 0.20 when 'baseline' then 0.35 when 'counterfactual' then 0.45 when 'adverse' then 0.65 when 'stress' then 0.85 else 0.90 end;
      v_novelty := least(1,0.15 + (v_i::numeric / greatest(v_target,1)) * 0.65);
      v_plausibility := case v_template.scenario_class when 'baseline' then 0.92 when 'optimistic' then 0.78 when 'adverse' then 0.82 when 'stress' then 0.68 when 'edge' then 0.55 else 0.80 end;

      insert into constitution.generated_scenarios(
        id,scenario_code,request_id,run_id,template_id,scenario_class,title,narrative,
        initial_state,participant_state,environment_state,decision_path,assumptions,evidence_refs,
        uncertainty_factors,probability_prior,severity_score,novelty_score,plausibility_score,
        constitutional_status,quality_status)
      values(
        v_scenario_id,
        'ESL-SCN-'||to_char(clock_timestamp(),'YYYYMMDDHH24MISSMS')||'-'||lpad(v_i::text,3,'0')||'-'||substr(v_scenario_id::text,1,6),
        p_request_id,v_run_id,v_template.id,v_template.scenario_class,
        v_template.name||' '||v_i,
        v_template.description||' Objective: '||v_request.objective,
        v_request.baseline_facts,
        jsonb_build_object('behavioral_profiles','[]'::jsonb,'counterparty_state','unknown','confidence',1-v_request.uncertainty_budget),
        jsonb_build_object('constraints',v_request.known_constraints,'uncertainty_budget',v_request.uncertainty_budget),
        jsonb_build_array(jsonb_build_object('step',1,'decision_option_index',((v_i-1) % jsonb_array_length(v_request.decision_options)),'option',v_request.decision_options->((v_i-1) % jsonb_array_length(v_request.decision_options)))),
        jsonb_build_array(jsonb_build_object('type','scenario_class_assumption','value',v_template.scenario_class,'explicit',true)),
        jsonb_build_array(jsonb_build_object('source','scenario_generation_request','request_id',p_request_id)),
        jsonb_build_array(jsonb_build_object('factor','human_response','range','bounded'),jsonb_build_object('factor','external_environment','range','bounded')),
        v_probability,v_severity,v_novelty,v_plausibility,
        'review_required','pending');

      insert into constitution.scenario_variables(scenario_id,variable_key,variable_type,value,source_type,confidence,sensitivity)
      values
      (v_scenario_id,'uncertainty_budget','fixed',to_jsonb(v_request.uncertainty_budget),'fact',1,0.8),
      (v_scenario_id,'scenario_class','categorical',to_jsonb(v_template.scenario_class),'policy',1,0.4),
      (v_scenario_id,'selected_decision_option','categorical',v_request.decision_options->((v_i-1) % jsonb_array_length(v_request.decision_options)),'fact',1,0.9);
    end loop;
  end loop;

  insert into constitution.scenario_quality_reviews(
    scenario_id,reviewer_type,reviewer_reference,factual_grounding,internal_consistency,
    diversity_contribution,non_manipulation,constitutional_compliance,findings,disposition)
  select id,'rule_engine','ESL-002.1',
    case when initial_state='{}'::jsonb then 0.5 else 0.9 end,
    0.9, greatest(0.5,novelty_score),1.0,0.9,
    case when initial_state='{}'::jsonb then '[{"severity":"warning","issue":"baseline facts are empty"}]'::jsonb else '[]'::jsonb end,
    case when plausibility_score>=0.6 then 'accept' else 'revise' end
  from constitution.generated_scenarios where run_id=v_run_id;

  update constitution.generated_scenarios s set
    quality_status = case when q.disposition='accept' then 'accepted' else 'needs_revision' end,
    constitutional_status = case when q.constitutional_compliance>=0.9 then 'permitted' else 'review_required' end
  from constitution.scenario_quality_reviews q
  where q.scenario_id=s.id and s.run_id=v_run_id and q.reviewer_type='rule_engine';

  update constitution.scenario_generation_runs set
    status='completed', completed_at=clock_timestamp(),
    generation_metrics=jsonb_build_object(
      'scenarios_generated',(select count(*) from constitution.generated_scenarios where run_id=v_run_id),
      'classes_covered',(select count(distinct scenario_class) from constitution.generated_scenarios where run_id=v_run_id),
      'accepted',(select count(*) from constitution.generated_scenarios where run_id=v_run_id and quality_status='accepted'),
      'average_plausibility',(select round(avg(plausibility_score),4) from constitution.generated_scenarios where run_id=v_run_id)
    ) where id=v_run_id;
  update constitution.scenario_generation_requests set status='generated',updated_at=clock_timestamp() where id=p_request_id;
  return v_run_id;
exception when others then
  update constitution.scenario_generation_runs set status='failed',error_detail=sqlerrm,completed_at=clock_timestamp() where id=v_run_id;
  update constitution.scenario_generation_requests set status='failed',updated_at=clock_timestamp() where id=p_request_id;
  raise;
end;
$function$;
CREATE OR REPLACE FUNCTION constitution.run_supabase_discovery(p_source_code text DEFAULT 'SRC-SUPABASE'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'constitution', 'public', 'pg_catalog'
AS $function$
declare
  v_source_id uuid;
  v_snapshot_id uuid;
  v_org_id uuid;
  v_run_started timestamptz := clock_timestamp();
  v_seen integer := 0;
  v_created integer := 0;
  v_updated integer := 0;
  v_missing integer := 0;
  v_relationships integer := 0;
  v_schema record;
  v_object record;
  v_missing_entity record;
  v_schema_entity_id uuid;
  v_entity_id uuid;
  v_existing_hash text;
  v_hash text;
  v_enterprise_id text;
begin
  if not pg_try_advisory_xact_lock(hashtext('constitution.run_supabase_discovery:' || p_source_code)) then
    return jsonb_build_object('status','skipped','reason','discovery_already_running','source_code',p_source_code);
  end if;

  select id into v_source_id from constitution.twin_source_systems where source_code = p_source_code;
  if v_source_id is null then raise exception 'Unknown source system: %', p_source_code; end if;
  select id into v_org_id from constitution.ai_organizations where organization_code = 'AIO-002';

  insert into constitution.twin_discovery_snapshots(source_system_id,status,started_at,source_cursor,evidence)
  values(v_source_id,'running',v_run_started,'{}'::jsonb,
    jsonb_build_object('discovery_agent','AIO-002','source',p_source_code,'mode','scheduled_metadata_sync'))
  returning id into v_snapshot_id;

  for v_schema in
    select n.nspname as schema_name
    from pg_namespace n
    where n.nspname not in ('pg_catalog','information_schema','pg_toast')
      and n.nspname not like 'pg_temp_%' and n.nspname not like 'pg_toast_temp_%'
    order by n.nspname
  loop
    v_seen := v_seen + 1;
    v_enterprise_id := 'ENT-DB-SCHEMA-' || upper(regexp_replace(v_schema.schema_name,'[^a-zA-Z0-9]+','-','g'));
    v_hash := md5(v_schema.schema_name);

    select id,content_hash into v_schema_entity_id,v_existing_hash
    from constitution.twin_entities
    where source_system_id=v_source_id and source_native_id='schema:'||v_schema.schema_name;

    if v_schema_entity_id is null then
      insert into constitution.twin_entities(enterprise_id,entity_type,name,status,source_system_id,source_native_id,canonical_uri,description,criticality,owner_ai_organization_id,attributes,tags,content_hash,last_seen_at)
      values(v_enterprise_id,'database_schema',v_schema.schema_name,'active',v_source_id,'schema:'||v_schema.schema_name,
        'supabase://schema/'||v_schema.schema_name,'PostgreSQL schema discovered from Supabase metadata','normal',v_org_id,
        jsonb_build_object('schema',v_schema.schema_name),array['supabase','discovered'],v_hash,v_run_started)
      returning id into v_schema_entity_id;
      v_created := v_created + 1;
      insert into constitution.twin_discovery_findings(snapshot_id,finding_type,severity,entity_id,title,evidence,status)
      values(v_snapshot_id,'new_entity','info',v_schema_entity_id,'New database schema discovered',jsonb_build_object('schema',v_schema.schema_name),'open');
    else
      update constitution.twin_entities
      set last_seen_at=v_run_started,status='active',retired_at=null,content_hash=v_hash,
          attributes=(attributes-'missing_since'-'missing_detection_count'-'last_missing_snapshot_id'),updated_at=clock_timestamp()
      where id=v_schema_entity_id;
      update constitution.twin_discovery_findings set status='resolved',resolved_at=clock_timestamp()
      where entity_id=v_schema_entity_id and finding_type='missing_entity' and status in ('open','acknowledged');
      if v_existing_hash is distinct from v_hash then v_updated := v_updated + 1; end if;
    end if;

    for v_object in
      select c.relname as object_name,
        case c.relkind when 'r' then 'database_table' when 'p' then 'database_table' when 'v' then 'database_view' when 'm' then 'database_view' else 'database_object' end as entity_type,
        c.relkind::text as relkind, coalesce(obj_description(c.oid,'pg_class'),'') as description
      from pg_class c join pg_namespace n on n.oid=c.relnamespace
      where n.nspname=v_schema.schema_name and c.relkind in ('r','p','v','m') order by c.relname
    loop
      v_seen := v_seen + 1;
      v_hash := md5(v_schema.schema_name||'.'||v_object.object_name||':'||v_object.relkind||':'||v_object.description);
      v_enterprise_id := 'ENT-DB-' || case when v_object.entity_type='database_table' then 'TABLE-' else 'VIEW-' end ||
        upper(regexp_replace(v_schema.schema_name||'-'||v_object.object_name,'[^a-zA-Z0-9]+','-','g'));

      select id,content_hash into v_entity_id,v_existing_hash
      from constitution.twin_entities
      where source_system_id=v_source_id and source_native_id=v_object.entity_type||':'||v_schema.schema_name||'.'||v_object.object_name;

      if v_entity_id is null then
        insert into constitution.twin_entities(enterprise_id,entity_type,name,status,source_system_id,source_native_id,canonical_uri,description,criticality,owner_ai_organization_id,attributes,tags,content_hash,last_seen_at)
        values(v_enterprise_id,v_object.entity_type,v_schema.schema_name||'.'||v_object.object_name,'active',v_source_id,
          v_object.entity_type||':'||v_schema.schema_name||'.'||v_object.object_name,
          'supabase://'||v_object.entity_type||'/'||v_schema.schema_name||'/'||v_object.object_name,
          nullif(v_object.description,''),'normal',v_org_id,
          jsonb_build_object('schema',v_schema.schema_name,'name',v_object.object_name,'relkind',v_object.relkind),
          array['supabase','discovered'],v_hash,v_run_started)
        returning id into v_entity_id;
        v_created := v_created + 1;
        insert into constitution.twin_discovery_findings(snapshot_id,finding_type,severity,entity_id,title,evidence,status)
        values(v_snapshot_id,'new_entity','info',v_entity_id,'New database object discovered',
          jsonb_build_object('schema',v_schema.schema_name,'object',v_object.object_name,'type',v_object.entity_type),'open');
      else
        update constitution.twin_entities
        set last_seen_at=v_run_started,status='active',retired_at=null,content_hash=v_hash,
            attributes=(jsonb_build_object('schema',v_schema.schema_name,'name',v_object.object_name,'relkind',v_object.relkind)
              || (attributes-'missing_since'-'missing_detection_count'-'last_missing_snapshot_id')),
            updated_at=clock_timestamp()
        where id=v_entity_id;
        update constitution.twin_discovery_findings set status='resolved',resolved_at=clock_timestamp()
        where entity_id=v_entity_id and finding_type='missing_entity' and status in ('open','acknowledged');
        if v_existing_hash is distinct from v_hash then
          v_updated := v_updated + 1;
          insert into constitution.twin_discovery_findings(snapshot_id,finding_type,severity,entity_id,title,evidence,status)
          values(v_snapshot_id,'changed_entity','low',v_entity_id,'Database object metadata changed',
            jsonb_build_object('schema',v_schema.schema_name,'object',v_object.object_name),'open');
        end if;
      end if;

      insert into constitution.twin_relationships(source_entity_id,target_entity_id,relationship_type,directionality,strength,confidence,source_system_id,evidence,metadata)
      values(v_schema_entity_id,v_entity_id,'contains','directed',1,1,v_source_id,
        jsonb_build_object('source','pg_catalog','snapshot_id',v_snapshot_id),'{}'::jsonb)
      on conflict (source_entity_id,target_entity_id,relationship_type)
      do update set valid_to=null,confidence=1,evidence=excluded.evidence,updated_at=clock_timestamp();
      v_relationships := v_relationships + 1;
    end loop;
  end loop;

  for v_missing_entity in
    select e.id,e.name,e.entity_type,e.criticality,
      coalesce((e.attributes->>'missing_detection_count')::integer,0) as prior_missing_count
    from constitution.twin_entities e
    where e.source_system_id=v_source_id and e.tags @> array['discovered']::text[]
      and e.entity_type in ('database_schema','database_table','database_view','database_object')
      and e.last_seen_at < v_run_started and e.status <> 'retired'
  loop
    v_missing := v_missing + 1;
    update constitution.twin_entities
    set status=case when v_missing_entity.prior_missing_count >= 2 then 'retired' else 'degraded' end,
        retired_at=case when v_missing_entity.prior_missing_count >= 2 then clock_timestamp() else null end,
        attributes=attributes||jsonb_build_object(
          'missing_since',coalesce(attributes->'missing_since',to_jsonb(v_run_started)),
          'missing_detection_count',v_missing_entity.prior_missing_count+1,
          'last_missing_snapshot_id',v_snapshot_id),updated_at=clock_timestamp()
    where id=v_missing_entity.id;
    if not exists (
      select 1 from constitution.twin_discovery_findings f
      where f.entity_id=v_missing_entity.id and f.finding_type='missing_entity' and f.status in ('open','acknowledged')
    ) then
      insert into constitution.twin_discovery_findings(snapshot_id,finding_type,severity,entity_id,title,detail,evidence,status)
      values(v_snapshot_id,'missing_entity',case when v_missing_entity.criticality in ('high','critical') then 'high' else 'moderate' end,
        v_missing_entity.id,'Previously discovered database object is missing',
        v_missing_entity.name||' was not observed during the current discovery pass.',
        jsonb_build_object('entity_name',v_missing_entity.name,'entity_type',v_missing_entity.entity_type,'missing_count',v_missing_entity.prior_missing_count+1),'open');
    end if;
  end loop;

  update constitution.twin_relationships r set valid_to=coalesce(r.valid_to,v_run_started),updated_at=clock_timestamp()
  where r.source_system_id=v_source_id and r.valid_to is null
    and exists(select 1 from constitution.twin_entities e where e.id in (r.source_entity_id,r.target_entity_id) and e.status in ('degraded','retired'));

  update constitution.twin_source_systems set last_discovered_at=clock_timestamp(),status='connected',updated_at=clock_timestamp() where id=v_source_id;
  update constitution.twin_discovery_snapshots
  set status='succeeded',completed_at=clock_timestamp(),entities_seen=v_seen,entities_created=v_created,
      entities_updated=v_updated,entities_missing=v_missing,relationships_created=v_relationships,
      evidence=evidence||jsonb_build_object('completed_by','AIO-002','mode','scheduled_metadata_sync',
        'missing_object_policy','degrade_then_retire_after_three_consecutive_misses')
  where id=v_snapshot_id;

  return jsonb_build_object('status','succeeded','snapshot_id',v_snapshot_id,'entities_seen',v_seen,
    'entities_created',v_created,'entities_updated',v_updated,'entities_missing',v_missing,
    'relationships_processed',v_relationships);
exception when others then
  if v_snapshot_id is not null then
    update constitution.twin_discovery_snapshots set status='failed',completed_at=clock_timestamp(),error_detail=sqlerrm where id=v_snapshot_id;
  end if;
  raise;
end;
$function$;
CREATE OR REPLACE FUNCTION constitution.score_strategy_candidate(p_experiment_id uuid, p_candidate_id uuid, p_metric_results jsonb, p_constraint_results jsonb DEFAULT '{}'::jsonb, p_trial_count integer DEFAULT 1000, p_confidence numeric DEFAULT 0.75)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'constitution', 'public'
AS $function$
declare
  v_weights jsonb;
  v_key text;
  v_weight numeric;
  v_metric numeric;
  v_weight_total numeric := 0;
  v_score numeric := 0;
  v_penalty numeric := 0;
  v_eval_id uuid;
  v_scenario_id uuid;
begin
  select objective_weights, scenario_id into v_weights, v_scenario_id
  from constitution.strategy_evolution_experiments where id=p_experiment_id;
  if v_weights is null then raise exception 'Experiment not found'; end if;
  if not exists(select 1 from constitution.strategy_candidates where id=p_candidate_id and experiment_id=p_experiment_id) then
    raise exception 'Candidate does not belong to experiment';
  end if;

  for v_key,v_weight in select key, value::numeric from jsonb_each_text(v_weights) loop
    v_metric := coalesce((p_metric_results->>v_key)::numeric,0);
    v_metric := greatest(0,least(1,v_metric));
    v_weight_total := v_weight_total + abs(v_weight);
    v_score := v_score + (v_metric * v_weight);
  end loop;
  if v_weight_total > 0 then v_score := v_score / v_weight_total; end if;

  -- A failed hard constraint creates a severe but transparent penalty.
  select coalesce(sum(case when value::boolean=false then 0.25 else 0 end),0)
  into v_penalty from jsonb_each_text(p_constraint_results);

  insert into constitution.strategy_simulation_evaluations(
    experiment_id,candidate_id,scenario_id,trial_count,metric_results,constraint_results,
    expected_value,risk_adjusted_score,confidence
  ) values (
    p_experiment_id,p_candidate_id,v_scenario_id,greatest(p_trial_count,0),p_metric_results,p_constraint_results,
    round(v_score,6),round(greatest(-1,least(1,v_score-v_penalty)),6),greatest(0,least(1,p_confidence))
  )
  on conflict (experiment_id,candidate_id,scenario_id) do update set
    trial_count=excluded.trial_count, metric_results=excluded.metric_results,
    constraint_results=excluded.constraint_results, expected_value=excluded.expected_value,
    risk_adjusted_score=excluded.risk_adjusted_score, confidence=excluded.confidence,
    created_at=now()
  returning id into v_eval_id;
  return v_eval_id;
end $function$;
CREATE OR REPLACE FUNCTION constitution.select_strategy_champion(p_experiment_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'constitution', 'public'
AS $function$
declare
  v_candidate uuid;
  v_decision uuid;
  v_ranking jsonb;
  v_failed_constraints int;
begin
  select count(*) into v_failed_constraints
  from constitution.strategy_simulation_evaluations e,
       lateral jsonb_each_text(e.constraint_results) x
  where e.experiment_id=p_experiment_id and x.value::boolean=false;

  select e.candidate_id into v_candidate
  from constitution.strategy_simulation_evaluations e
  where e.experiment_id=p_experiment_id
    and not exists (select 1 from jsonb_each_text(e.constraint_results) x where x.value::boolean=false)
  order by e.risk_adjusted_score desc, e.confidence desc, e.created_at desc
  limit 1;
  if v_candidate is null then raise exception 'No eligible candidate with all hard constraints satisfied'; end if;

  select jsonb_agg(jsonb_build_object(
    'candidate_id',e.candidate_id,'candidate_code',c.candidate_code,
    'risk_adjusted_score',e.risk_adjusted_score,'expected_value',e.expected_value,'confidence',e.confidence
  ) order by e.risk_adjusted_score desc)
  into v_ranking
  from constitution.strategy_simulation_evaluations e
  join constitution.strategy_candidates c on c.id=e.candidate_id
  where e.experiment_id=p_experiment_id;

  update constitution.strategy_candidates set status='challenger'
  where experiment_id=p_experiment_id and status in ('candidate','eligible','champion','challenger');
  update constitution.strategy_candidates set status='champion' where id=v_candidate;

  insert into constitution.strategy_selection_decisions(
    experiment_id,selected_candidate_id,ranking,selection_rationale,approval_status
  ) values (
    p_experiment_id,v_candidate,coalesce(v_ranking,'[]'::jsonb),
    'Selected highest risk-adjusted candidate satisfying every recorded hard constraint. Human approval remains required.',
    'pending'
  ) returning id into v_decision;

  update constitution.strategy_evolution_experiments
  set status='awaiting_approval',updated_at=now() where id=p_experiment_id;
  return v_decision;
end $function$;
CREATE OR REPLACE FUNCTION constitution.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'constitution', 'pg_temp'
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$;
CREATE OR REPLACE FUNCTION constitution.touch_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'pg_catalog', 'constitution'
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$;

